        if (parts.length >= 4) {
          final dayNum = parts[0];
          final monthStr = parts[1];
          final dayName = parts[3];

          final monthShort = monthStr.length > 3 ? monthStr.substring(0, 3) : monthStr;
          final dayShort = dayName.length > 3 ? dayName.substring(0, 3) : dayName;

          return "$dayNum $monthShort\n$dayShort";
        }
      }
    } catch (e) {
      debugPrint("Error formatting row date: $e");
    }
    final kisa = item['MiladiTarihKisa'] as String? ?? '';
